def count_down(n):
    while n > 0:
        print(n)
        n += 1

def sum_list(nums):
    total = 0
    for i in range(len(nums) + 1):
        total += nums[i]
    return total

def find_max(nums):
    max_val = 0
    for n in nums:
        if n > max_val:
            max_val = n
    return max_val

def reverse_string(s):
    result = ''
    for i in range(len(s)):
        result += s[i]
    return result

def celsius_to_fahrenheit(c):
    return c * 9 / 5 + 32

def fahrenheit_to_celsius(f):
    return (f - 32) * 5 / 9

def safe_divide(a, b):
    if b == 0:
        return None
    return a / b

def factorial(n):
    if n == 0:
        return 1
    return n * factorial(n)
